// Get Pinterest URL from either manual input or webhook
const items = $input.all();
const item = items[0];

// For webhook: URL comes from body.pinterest_url
// For manual: set a test URL here
let pinterestUrl = '';

if (item.json.body && item.json.body.pinterest_url) {
  pinterestUrl = item.json.body.pinterest_url;
} else if (item.json.pinterest_url) {
  pinterestUrl = item.json.pinterest_url;
} else {
  // Test URL for manual trigger
  pinterestUrl = 'https://pin.it/example';
}

// Validate URL
if (!pinterestUrl || !pinterestUrl.includes('pin')) {
  throw new Error('Invalid Pinterest URL: ' + pinterestUrl);
}

return [{ json: { pinterest_url: pinterestUrl, timestamp: new Date().toISOString() } }];

// Extract image URL from Pinterest
const pinUrl = $input.first().json.pinterest_url;
const timestamp = $input.first().json.timestamp;

// Try oEmbed API first
const oembedUrl = `https://www.pinterest.com/oembed.json?url=${encodeURIComponent(pinUrl)}`;

return [{
  json: {
    pinterest_url: pinUrl,
    oembed_url: oembedUrl,
    timestamp
  }
}];

// Extract and upgrade image URL from oEmbed response
const data = $input.first().json;
const pinterest_url = $('Prepare oEmbed Request').first().json.pinterest_url;
const timestamp = $('Prepare oEmbed Request').first().json.timestamp;

let imageUrl = data.thumbnail_url || data.url || '';

if (!imageUrl) {
  throw new Error('Could not extract image URL from Pinterest: ' + pinterest_url);
}

// Upgrade to highest quality
const upgrades = [
  ['236x', 'originals'],
  ['474x', 'originals'],
  ['736x', 'originals'],
  ['170x', 'originals']
];
for (const [low, high] of upgrades) {
  imageUrl = imageUrl.replace(low, high);
}

const title = data.title || 'Fashion Outfit';
const author = data.author_name || '';

console.log('Extracted image:', imageUrl);

return [{
  json: {
    pinterest_url,
    image_url: imageUrl,
    title,
    author,
    timestamp
  }
}];

// Upload downloaded image to catbox.moe for public URL
const imageData = $input.first().binary;
const prevJson = $('Extract Image URL').first().json;

if (!imageData || !imageData.data) {
  throw new Error('No image data received');
}

// Return image data for upload
return [{
  json: {
    ...prevJson,
    has_image: true
  },
  binary: imageData
}];

// Get public URL from upload response
const uploadResponse = $input.first().json;
const prevData = $('Extract Image URL').first().json;

let publicUrl = '';

// catbox returns plain text URL
if (typeof uploadResponse === 'string' && uploadResponse.startsWith('https://')) {
  publicUrl = uploadResponse.trim();
} else if (uploadResponse.body && uploadResponse.body.startsWith('https://')) {
  publicUrl = uploadResponse.body.trim();
} else {
  // Fallback: use original Pinterest image URL directly
  publicUrl = prevData.image_url;
  console.log('Using original Pinterest URL as fallback');
}

console.log('Public URL:', publicUrl);

return [{
  json: {
    ...prevData,
    public_image_url: publicUrl
  }
}];

