// Parse OpenAI response and build Instagram caption
const openaiResponse = $input.first().json;
const prevData = $('Get Public URL').first().json;

let aiContent = {};

try {
  const rawText = openaiResponse.choices[0].message.content;
  const cleaned = rawText.replace(/```json/g,'').replace(/```/g,'').trim();
  aiContent = JSON.parse(cleaned);
} catch(e) {
  console.log('JSON parse failed, using defaults:', e.message);
  aiContent = {
    title: 'Stylish Outfit of the Day',
    caption: 'Check out this amazing outfit! Perfect for any occasion.',
    call_to_action: 'Comment LINK for shopping details',
    hashtags: '#fashion #style #outfit #ootd #india #fashionblogger #trending #viral #instafashion #outfitoftheday #fashionista #streetstyle #lookbook #fashionlover #stylish',
    outfit_details: { style: 'Casual', occasion: 'Daily', budget: 'Budget Friendly' }
  };
}

// Build full Instagram caption
const fullCaption = `${aiContent.title}\n\n${aiContent.caption}\n\n${aiContent.call_to_action}\n\n${aiContent.hashtags}`;

console.log('Generated caption:', fullCaption.substring(0, 100));

return [{
  json: {
    ...prevData,
    ai_title: aiContent.title,
    ai_caption: aiContent.caption,
    ai_cta: aiContent.call_to_action,
    ai_hashtags: aiContent.hashtags,
    outfit_details: aiContent.outfit_details,
    full_caption: fullCaption
  }
}];

// Build final log entry
const publishResponse = $input.first().json;
const captionData = $('Parse AI Caption').first().json;

const logEntry = {
  success: true,
  instagram_post_id: publishResponse.id || 'unknown',
  pinterest_url: captionData.pinterest_url,
  image_url: captionData.public_image_url,
  title: captionData.ai_title,
  caption: captionData.full_caption,
  posted_at: new Date().toISOString()
};

console.log('✅ Successfully posted to Instagram!');
console.log('Post ID:', logEntry.instagram_post_id);
console.log('Title:', logEntry.title);

return [{ json: logEntry }];

// Handle errors gracefully
const error = $input.first().json;
console.error('Pipeline failed:', JSON.stringify(error));

return [{
  json: {
    success: false,
    error: error.message || 'Unknown error',
    timestamp: new Date().toISOString()
  }
}];
